#!/usr/bin/env node
/**
 * Generates missing Bible character profiles for bible-characters.json
 * Reads characterGroups, finds characters without entries, adds embedded profiles
 */

const fs = require('fs');
const path = require('path');

const DATA_PATH = path.join(__dirname, '../bible-characters.json');
const IMAGE_BASE = 'https://raw.githubusercontent.com/jacixn/biblely-character-data/main/profileImage';
const AUDIO_BASE = 'https://raw.githubusercontent.com/jacixn/project-1/main/audio-files/bible-characters';

function toSlug(name) {
  return name
    .toLowerCase()
    .replace(/'/g, '')
    .replace(/[()]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '');
}

