  "Jeremiah": { name: "Jeremiah - The Weeping Prophet", story: "Jeremiah was called as a youth to prophesy (Jeremiah 1-52). He prophesied Jerusalem's fall. He was opposed, beaten, and imprisoned. He bought a field as a sign of hope. He wrote to the exiles. He was taken to Egypt against his will. He lamented the destruction. He foretold a new covenant written on the heart.", themes: ["Call: He was set apart before birth", "Suffering: He endured rejection for his message", "Hope: He promised restoration and a new covenant"], culturalImpact: "Jeremiah's laments have comforted those who mourn.", verses: ["Jeremiah 1:4-10", "Jeremiah 31:31-34", "Jeremiah 32:1-15"] },
